import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { apiClient, authService } from "@/App";
import { toast } from "sonner";
import {
  Plus, Search, Users, Bell, FileText, ClipboardCheck,
  Heart, Shield, Clock
} from "lucide-react";

const SecretaryPortal = () => {
  const [students, setStudents] = useState([]);
  const [announcements, setAnnouncements] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [studentDialogOpen, setStudentDialogOpen] = useState(false);
  const [announcementDialogOpen, setAnnouncementDialogOpen] = useState(false);
  const user = authService.getUser();

  const kenyaClasses = [
    "PP1","PP2","Grade 1","Grade 2","Grade 3","Grade 4","Grade 5","Grade 6",
    "Grade 7","Grade 8","Grade 9","Grade 10","Grade 11","Grade 12"
  ];

  const [studentForm, setStudentForm] = useState({
    admission_number: "", full_name: "", date_of_birth: "", gender: "male",
    class_name: "", stream: "",
    guardian_name: "", guardian_phone: "", guardian_email: "", guardian_relationship: "parent"
  });

  const [announcementForm, setAnnouncementForm] = useState({
    title: "", content: "", target_audience: "all", target_class: "", priority: "normal"
  });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [studentsRes, announcementsRes] = await Promise.all([
        apiClient.get("/students?approval_status=all"),
        apiClient.get("/announcements?approval_status=all"),
      ]);
      setStudents(studentsRes.data);
      setAnnouncements(announcementsRes.data);
    } catch (error) {
      toast.error("Failed to fetch data");
    } finally {
      setLoading(false);
    }
  };

  const handleSubmitStudent = async (e) => {
    e.preventDefault();
    try {
      const res = await apiClient.post("/students", studentForm);
      toast.success(
        res.data.approval_status === "pending"
          ? "Student submitted for approval"
          : "Student added successfully"
      );
      setStudentDialogOpen(false);
      setStudentForm({
        admission_number: "", full_name: "", date_of_birth: "", gender: "male",
        class_name: "", stream: "",
        guardian_name: "", guardian_phone: "", guardian_email: "", guardian_relationship: "parent"
      });
      fetchData();
    } catch (error) {
      toast.error(error.response?.data?.detail || "Failed to add student");
    }
  };

  const handleSubmitAnnouncement = async (e) => {
    e.preventDefault();
    try {
      const res = await apiClient.post("/announcements", announcementForm);
      toast.success(
        res.data.approval_status === "pending"
          ? "Announcement submitted for approval"
          : "Announcement posted"
      );
      setAnnouncementDialogOpen(false);
      setAnnouncementForm({
        title: "", content: "", target_audience: "all", target_class: "", priority: "normal"
      });
      fetchData();
    } catch (error) {
      toast.error(error.response?.data?.detail || "Failed to post announcement");
    }
  };

  const filteredStudents = students.filter(s =>
    s.full_name?.toLowerCase().includes(search.toLowerCase()) ||
    s.admission_number?.toLowerCase().includes(search.toLowerCase())
  );

  const approvalColor = (status) => {
    if (status === "approved") return "bg-green-500/15 text-green-400";
    if (status === "rejected") return "bg-red-500/15 text-red-400";
    return "bg-yellow-500/15 text-yellow-400";
  };

  const pendingStudents = students.filter(s => s.approval_status === "pending").length;
  const approvedStudents = students.filter(s => s.approval_status === "approved").length;
  const pendingAnnouncements = announcements.filter(a => a.approval_status === "pending").length;

  return (
    <div className="space-y-6" data-testid="secretary-portal">

      {/* HEADER */}
      <div className="bg-gradient-to-r from-amber-600/20 to-orange-600/20 border border-amber-500/20 rounded-2xl p-8">
        <h2 className="text-4xl font-bold text-white">Secretary Portal</h2>
        <p className="text-amber-300/70 mt-2 text-lg">
          Welcome, {user?.full_name}
        </p>
        <p className="text-amber-400/50 text-sm">
          Student records & announcements management
        </p>
      </div>

      {/* STATS */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">

        <Card className="bg-[#1A2332] border-[#1E293B] border-l-4 border-l-amber-500">
          <CardHeader className="pb-2">
            <CardTitle className="text-slate-400 text-sm">Total Students</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold text-white">{students.length}</div>
          </CardContent>
        </Card>

        <Card className="bg-[#1A2332] border-[#1E293B] border-l-4 border-l-green-500">
          <CardHeader className="pb-2">
            <CardTitle className="text-slate-400 text-sm">Approved</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold text-green-400">{approvedStudents}</div>
          </CardContent>
        </Card>

        <Card className="bg-[#1A2332] border-[#1E293B] border-l-4 border-l-yellow-500">
          <CardHeader className="pb-2">
            <CardTitle className="text-slate-400 text-sm">Pending</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold text-yellow-400">{pendingStudents}</div>
          </CardContent>
        </Card>

        <Card className="bg-[#1A2332] border-[#1E293B] border-l-4 border-l-blue-500">
          <CardHeader className="pb-2">
            <CardTitle className="text-slate-400 text-sm">Announcements</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold text-white">{announcements.length}</div>
          </CardContent>
        </Card>
      </div>

      {/* TABS */}
      <div className="space-y-6">

        {/* STUDENTS */}
        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardHeader>
            <div className="flex justify-between items-center gap-4 flex-wrap">
              <CardTitle className="text-white">Student Records</CardTitle>

              <div className="flex gap-3 items-center">
                <Input
                  placeholder="Search students..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="w-64"
                  data-testid="search-students-input"
                />

                <Dialog open={studentDialogOpen} onOpenChange={setStudentDialogOpen}>
                  <DialogTrigger asChild>
                    <Button className="bg-amber-600 hover:bg-amber-700">
                      <Plus className="w-4 h-4 mr-2" /> Add Student
                    </Button>
                  </DialogTrigger>

                  <DialogContent className="max-w-2xl">
                    <DialogHeader>
                      <DialogTitle>Register Student</DialogTitle>
                    </DialogHeader>

                    <form onSubmit={handleSubmitStudent} className="space-y-4">
                      <Input placeholder="Admission Number"
                        value={studentForm.admission_number}
                        onChange={(e) => setStudentForm({...studentForm, admission_number: e.target.value})}
                        required
                      />

                      <Input placeholder="Full Name"
                        value={studentForm.full_name}
                        onChange={(e) => setStudentForm({...studentForm, full_name: e.target.value})}
                        required
                      />

                      <Input type="date"
                        value={studentForm.date_of_birth}
                        onChange={(e) => setStudentForm({...studentForm, date_of_birth: e.target.value})}
                        required
                      />

                      <Select value={studentForm.class_name}
                        onValueChange={(v) => setStudentForm({...studentForm, class_name: v})}>
                        <SelectTrigger>
                          <SelectValue placeholder="Select class" />
                        </SelectTrigger>
                        <SelectContent>
                          {kenyaClasses.map(c => (
                            <SelectItem key={c} value={c}>{c}</SelectItem>
                          ))}
                        </SelectContent>
                      </Select>

                      <Input placeholder="Guardian Name"
                        value={studentForm.guardian_name}
                        onChange={(e) => setStudentForm({...studentForm, guardian_name: e.target.value})}
                        required
                      />

                      <Input placeholder="Guardian Phone"
                        value={studentForm.guardian_phone}
                        onChange={(e) => setStudentForm({...studentForm, guardian_phone: e.target.value})}
                        required
                      />

                      <Button className="w-full bg-amber-600 hover:bg-amber-700">
                        Submit for Approval
                      </Button>
                    </form>
                  </DialogContent>
                </Dialog>
              </div>
            </div>
          </CardHeader>

          <CardContent>
            {loading ? (
              <div className="text-slate-400 text-center py-6">Loading...</div>
            ) : (
              <div className="space-y-3">
                {filteredStudents.map(s => (
                  <div key={s.id} className="p-4 border border-[#1E293B] rounded-lg flex justify-between">
                    <div>
                      <p className="text-white font-semibold">{s.full_name}</p>
                      <p className="text-slate-400 text-sm">{s.admission_number}</p>
                    </div>
                    <Badge className={approvalColor(s.approval_status)}>
                      {s.approval_status}
                    </Badge>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        {/* ANNOUNCEMENTS */}
        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardHeader>
            <CardTitle className="text-white">Announcements</CardTitle>
          </CardHeader>

          <CardContent>
            {announcements.length === 0 ? (
              <div className="text-slate-400 text-center py-6">
                No announcements yet
              </div>
            ) : (
              <div className="space-y-3">
                {announcements.map(a => (
                  <div key={a.id} className="p-4 border border-[#1E293B] rounded-lg">
                    <p className="text-white font-semibold">{a.title}</p>
                    <p className="text-slate-400 text-sm">{a.content}</p>
                    <Badge className={approvalColor(a.approval_status)}>
                      {a.approval_status}
                    </Badge>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

      </div>
    </div>
  );
};

export default SecretaryPortal;
